/*****************************************************************************
 * FUNCTION
 *  mmi_ucm_set_mute_action
 * DESCRIPTION
 *  execute mute action if permit passes
 * PARAMETERS
 *  void
 * RETURNS
 *  void
 *****************************************************************************/
void vapp_ucm_set_mute_action(VfxBool mute)
{
    /*----------------------------------------------------------------*/
    /* Local Variables                                                */
    /*----------------------------------------------------------------*/
    srv_ucm_result_enum option_check_result;
    
    /*----------------------------------------------------------------*/
    /* Code Body                                                      */
    /*----------------------------------------------------------------*/    
    option_check_result = mmi_ucm_mute_option(MMI_UCM_PERMIT_ONLY);

    if (SRV_UCM_RESULT_OK != option_check_result)
    {
        vapp_ucm_display_popup(option_check_result);
    }    
    else
    {
        if (!mute)
        {
            srv_speech_unmute_phone();
        }
        else
        {
            srv_speech_mute_phone();
        }
        mmi_popup_display((WCHAR*)((UI_string_type) GetString(STR_GLOBAL_DONE)), MMI_EVENT_SUCCESS, NULL);
    }
}
