VFX_IMPLEMENT_CLASS("VappUcmNCenterCell", VappUcmNCenterCell, VappNCenterOngoingDefaultCell);

void VappUcmNCenterCell::onInit()
{
    VappNCenterOngoingDefaultCell::onInit();
    mmi_frm_cb_reg_event(EVT_ID_VAPP_UCM_BG_RUN_START, VappUcmNCenterCell::onUcmBgEvents, this);
    mmi_frm_cb_reg_event(EVT_ID_VAPP_UCM_BG_RUN_END, VappUcmNCenterCell::onUcmBgEvents, this);
    m_timer = NULL;
    m_popup_id = 0;
}

void VappUcmNCenterCell::onDeinit()
{
    if(m_timer)
    {
        VFX_OBJ_CLOSE(m_timer);
    }

    VappNCenterOngoingDefaultCell::onDeinit();
}

mmi_ret closeproc(mmi_event_struct *evt)
{
    vcp_global_popup_cancel((VfxU32)evt->user_data);
    return MMI_RET_OK;
}

mmi_ret VappUcmNCenterCell::onUcmBgEvents(mmi_event_struct *evt)
{
    switch (evt->evt_id)
    {
        case EVT_ID_VAPP_UCM_BG_RUN_START:
        {
            /* shall set active index no matter create view (drag down NCenter) or not */
            VfxU8 total_calls = srv_ucm_query_call_count(SRV_UCM_ACTIVE_STATE, SRV_UCM_CALL_TYPE_NO_CSD, g_ucm_p->call_misc.index_list);
            if(total_calls == 0)
            {
                 total_calls = srv_ucm_query_call_count(SRV_UCM_HOLD_STATE, SRV_UCM_CALL_TYPE_NO_CSD, g_ucm_p->call_misc.index_list);
            }

            if (total_calls)
            {
                vapp_ucmapp_set_active_call_info(&(g_ucm_p->call_misc.index_list[0]));
            }

            VappUcmNCenterCell *ncell = (VappUcmNCenterCell*)evt->user_data;
            ncell->m_signalStateChanged.emit(ncell, VAPP_NCENTER_STATE_SHOW);
        }
            break;
        case EVT_ID_VAPP_UCM_BG_RUN_END:
        {
            VappUcmNCenterCell *ncell = (VappUcmNCenterCell*)evt->user_data;
            ncell->closePopup();
            ncell->m_signalStateChanged.emit(ncell, VAPP_NCENTER_STATE_HIDE);
        }
            break;
        default:
            break;
    }
    return MMI_RET_OK;
}

mmi_ret VappUcmNCenterCell::onCallStatusChange(mmi_event_struct *evt)
{
    VappUcmNCenterCell *nCell = (VappUcmNCenterCell*)(evt->user_data);

    if (!nCell)
    {
        return MMI_RET_OK;
    }

    if (nCell->m_callCount != 
        srv_ucm_query_call_count(SRV_UCM_CALL_STATE_CONNECTED, SRV_UCM_CALL_TYPE_NO_CSD, NULL))
    {
        nCell->m_callCount = 
            srv_ucm_query_call_count(SRV_UCM_CALL_STATE_CONNECTED, SRV_UCM_CALL_TYPE_NO_CSD, NULL);

        if(nCell->m_callCount)
        {
            nCell->updateView();
        }
    }

    return MMI_RET_OK;

}

void VappUcmNCenterCell::createView()
{
    m_callCount = srv_ucm_query_call_count(SRV_UCM_CALL_STATE_CONNECTED, SRV_UCM_CALL_TYPE_NO_CSD, NULL);

    if(m_callCount > 0)
    {
        m_isShow = VFX_TRUE;

        mmi_frm_cb_reg_event(EVT_ID_SRV_UCM_STATUS_CHANGE, VappUcmNCenterCell::onCallStatusChange, this);

        VappNCenterOngoingDefaultCell::createView();

        updateView();

        m_closeButton->m_signalClicked.connect(this, &VappUcmNCenterCell::onCloseButtonClick);

    }
}

void VappUcmNCenterCell::updateView()
{
    srv_ucm_group_info_struct group_info;
    srv_ucm_call_info_struct call_info;
    VfxS32 call_count = 0;
    
    VfxU8 total_calls = srv_ucm_query_call_count(SRV_UCM_ACTIVE_STATE, SRV_UCM_CALL_TYPE_NO_CSD, g_ucm_p->call_misc.index_list);
    if(total_calls == 0)
    {
         total_calls = srv_ucm_query_call_count(SRV_UCM_HOLD_STATE, SRV_UCM_CALL_TYPE_NO_CSD, g_ucm_p->call_misc.index_list);
    }
    VFX_ASSERT(total_calls);

    call_count = srv_ucm_query_group_data(g_ucm_p->call_misc.index_list[0].group_index, &group_info);
    srv_ucm_query_call_data(g_ucm_p->call_misc.index_list[0], &call_info);

    vapp_ucmapp_set_active_call_info(&(g_ucm_p->call_misc.index_list[0]));
    
    VfxWString main_str;
    if (group_info.call_state == SRV_UCM_HOLD_STATE)
    {
        setIcon(VfxImageSrc(IMG_ID_VAPP_UCM_NMGR_HELD));
        main_str = VFX_WSTR_RES(STR_ID_VAPP_UCM_NCENTER_STR_HELD);
    }
    else if(group_info.call_state == SRV_UCM_ACTIVE_STATE)
    {
        setIcon(VfxImageSrc(IMG_ID_VAPP_UCM_NMGR_ACTIVE));
        main_str = VFX_WSTR_RES(STR_ID_VAPP_UCM_NCENTER_STR_ACTIVE);
    }
    m_callStatus = main_str;
    m_callStartTime = getCallStartTime(g_ucm_p->call_misc.index_list[0].group_index);
    main_str += VFX_WSTR("(");
    VfxWString call_duration = getCallTimeDurationStr();
    main_str += call_duration;
    main_str += VFX_WSTR(")");
    setMainText(main_str);
    
    if(call_count > 1)
    {
        setSubText(VFX_WSTR_RES(STR_ID_VAPP_UCM_CONFERENCE));
    }
    else
    {
        setSubText(VFX_WSTR_MEM(call_info.remote_info.disp_name));
    }
    startCallTimer();

}

void VappUcmNCenterCell::closePopup()
{
    if(m_popup_id != 0)
    {
        mmi_event_struct postInvoke;
        MMI_FRM_INIT_EVENT(&postInvoke, 0);
        MMI_FRM_POST_EVENT(&postInvoke, closeproc, m_popup_id);
        m_popup_id = 0;
    }
}

void VappUcmNCenterCell::releaseView()
{
    if(m_isShow)
    {
        VFX_OBJ_CLOSE(m_timer);

        VappNCenterOngoingDefaultCell::releaseView();
        closePopup();
        mmi_frm_cb_dereg_event(EVT_ID_SRV_UCM_STATUS_CHANGE, VappUcmNCenterCell::onCallStatusChange, this);

        m_isShow = VFX_FALSE;
    }
}

void VappUcmNCenterCell::onNCenterLeave()
{
    if(srv_ucm_query_call_count(SRV_UCM_CALL_STATE_ALL, SRV_UCM_CALL_TYPE_ALL, NULL) > 0)
    {
        if (vapp_ucm_alive)
        {
            mmi_frm_set_active_group(vapp_ucm_get_app_id());
        }
        else
        {
            vapp_ucm_launch();
        }
    }
}

VfxBool VappUcmNCenterCell::onPenInput(VfxPenEvent &event)
{
    if (containPoint(event.getRelPos(this)) && event.type == VFX_PEN_EVENT_TYPE_UP)
    {
        requestNCenterLeave();
    }
    return VFX_TRUE;   
}

void VappUcmNCenterCell::startCallTimer(void)
{
    if(!m_timer)
    {
        VFX_OBJ_CREATE(m_timer, VfxTimer, this);
        m_timer->setDuration(990);
        m_timer->m_signalTick.connect(this, &VappUcmNCenterCell::onCallTimerTicked);
    }
    m_timer->start();
}

void VappUcmNCenterCell::stopCallTimer(void)
{
    if(m_timer)
    {
        m_timer->stop();
    }
}

void VappUcmNCenterCell::onCallTimerTicked(VfxTimer *timer)
{
    VfxWString main_str = m_callStatus;
    main_str += VFX_WSTR("(");
    main_str += getCallTimeDurationStr();
    main_str += VFX_WSTR(")");
    setMainText(main_str);
}

VfxWString VappUcmNCenterCell::getCallTimeDurationStr(void)
{
    VfxDateTime diff_time, current_time;
    VfxWChar    duration_str[16];

    current_time.setCurrentTime();
    current_time.getDiff(m_callStartTime, diff_time);
    diff_time.getDateTimeString(VFX_DATE_TIME_TIME_HOUR | VFX_DATE_TIME_TIME_MINUTE | VFX_DATE_TIME_TIME_SECOND | VFX_DATE_TIME_DURATION_FULL_FORMAT, 
                                duration_str, 16);
    return VFX_WSTR_MEM(duration_str);
}

void VappUcmNCenterCell::onCloseButtonClick(VfxObject *sender, VfxId id)
{
    VfxU8 total_calls = srv_ucm_query_call_count((srv_ucm_call_state_enum)(SRV_UCM_ACTIVE_STATE|SRV_UCM_HOLD_STATE), SRV_UCM_CALL_TYPE_NO_DATA_CSD, NULL);

    VfxResId end_call_string_id;
    if(total_calls > 1)
    {
        end_call_string_id = STR_ID_VAPP_UCM_END_ALL_CALLS;
    }
    else
    {
        end_call_string_id = STR_ID_VAPP_UCM_END_THIS_CALL_Q_MARK;
    }
    VfxWString end_call_string = VFX_WSTR_RES(end_call_string_id);
    end_call_string += VFX_WSTR_RES(STR_ID_VAPP_UCM_QUESTION_MARK);
    m_popup_id = vcp_global_popup_show_confirm_two_button_str(
        GRP_ID_ROOT,
        VCP_POPUP_TYPE_WARNING, 
        end_call_string, 
        VFX_WSTR_RES(end_call_string_id), 
        VFX_WSTR_RES(STR_GLOBAL_CANCEL),
        VCP_POPUP_BUTTON_TYPE_WARNING,
        VCP_POPUP_BUTTON_TYPE_CANCEL,
        &VappUcmNCenterCell::onPopupConfirm,
        this
        );
}

void VappUcmNCenterCell::onPopupConfirm(VfxId id, void *userData)
{
    if(id == VCP_CONFIRM_POPUP_BUTTON_USER_1)
    {
        vapp_ucm_end_all_action();
        //VappUcmNCenterCell* ptr = (VappUcmNCenterCell*)userData;
        //ptr->requestNCenterLeave();
    }
}


VFX_IMPLEMENT_CLASS("VappUcmScrnLockCard", VappUcmScrnLockCard, VappScreenLockCard);
void VappUcmScrnLockCard::onInit()
{
    VappScreenLockCard::onInit();

    VFX_OBJ_CREATE(m_imgIcon, VfxImageFrame, this);
    m_imgIcon->setResId(IMG_ID_VAPP_SCREEN_LOCK_CARD_ICON_PHONE);
    m_imgIcon->setAnchor(0.5, 0.5);
    m_imgIcon->setPos(getSize().width/2, getSize().height/2+VAPP_SCREEN_LOCK_CARD_OFFSET_BTW_IMG_AND_REAL_CARD/2);

    /*
    VFX_OBJ_CREATE(m_imgIconDot, VfxImageFrame, this);
    m_imgIconDot->setResId(IMG_ID_VAPP_SCREEN_LOCK_CARD_ICON_DOT1);
    m_imgIconDot->setAnchor(0.5, 0.5);
    m_imgIconDot->setPos(getSize().width/2, m_imgIcon->getPos().y+m_imgIcon->getSize().height+5);
    */
}

void VappUcmScrnLockCard::onUnlocked()
{
    m_signalUnlockCard.emit(m_actType);
}

void VappUcmScrnLockCard::setActType(VappUcmCallCellScrnUnlockTypeEnum act_type)
{
    m_actType = act_type;
    if(m_actType == VAPP_UCM_SCRN_UNLOCK_ACCEPT_CALL)
    {
        m_imgUnpress->setResId(IMG_ID_VAPP_SCREEN_LOCK_UNCLICKED_CARD1);
        m_imgIcon->setResId(IMG_ID_VAPP_UCM_LOCK_ACCEPT_CALL);
    }
    else
    {
        m_imgUnpress->setResId(IMG_ID_VAPP_SCREEN_LOCK_UNCLICKED_CARD3);
        m_imgIcon->setResId(IMG_ID_VAPP_UCM_LOCK_REJECT_CALL);
    }
}

VFX_IMPLEMENT_CLASS("VappUcmScrnLockUnlockCard", VappUcmScrnLockUnlockCard, VappScreenLockUnlockCard);
void VappUcmScrnLockUnlockCard::onUnlocked()
{
    m_signalUnlockCard.emit(VAPP_UCM_SCRN_UNLOCK_ONLY);
}

VFX_IMPLEMENT_CLASS("VappUcmScrnLockFrame", VappUcmScrnLockFrame, VappScreenLockFrame);
void VappUcmScrnLockFrame::onInit()
{
    VappScreenLockFrame::onInit();

    VFX_OBJ_CREATE(m_acceptCallCard, VappUcmScrnLockCard, this);
    m_acceptCallCard->setActType(VAPP_UCM_SCRN_UNLOCK_ACCEPT_CALL);

    VFX_OBJ_CREATE(m_unlockCard, VappUcmScrnLockUnlockCard, this);

    VFX_OBJ_CREATE(m_rejectCallCard, VappUcmScrnLockCard, this);
    m_rejectCallCard->setActType(VAPP_UCM_SCRN_UNLOCK_REJECT_CALL);

    addCard(m_acceptCallCard);
    addCard(m_unlockCard);
    addCard(m_rejectCallCard);

    m_acceptCallCard->m_signalUnlockCard.connect(this, &VappUcmScrnLockFrame::onCardUnlock);
    m_rejectCallCard->m_signalUnlockCard.connect(this, &VappUcmScrnLockFrame::onCardUnlock);
    m_unlockCard->m_signalUnlockCard.connect(this, &VappUcmScrnLockFrame::onCardUnlock);

    if(srv_ucm_query_call_count(SRV_UCM_INCOMING_STATE, SRV_UCM_CALL_TYPE_ALL, NULL) == 0)
    {
        m_acceptCallCard->setHidden(VFX_TRUE);
        m_rejectCallCard->setHidden(VFX_TRUE);
    }

    capture();
}

void VappUcmScrnLockFrame::onCardUnlock(VappUcmCallCellScrnUnlockTypeEnum unlock_type)
{
    m_signalScrnUnlock.emit(unlock_type);
}

void VappUcmScrnLockFrame::hideCard(VappUcmCallCellScrnUnlockTypeEnum card_type, VfxBool hide)
{
    if(card_type == VAPP_UCM_SCRN_UNLOCK_ACCEPT_CALL)
    {
        m_acceptCallCard->setHidden(hide);
    }
    else if(card_type == VAPP_UCM_SCRN_UNLOCK_REJECT_CALL)
    {
        m_rejectCallCard->setHidden(hide);
    }
    else if(card_type == VAPP_UCM_SCRN_UNLOCK_ONLY)
    {
        m_unlockCard->setHidden(hide);
    }
}

